import Database from 'better-sqlite3';
import path from 'path';
import { fileURLToPath } from 'url';
import { mkdirSync } from 'fs';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const DATA_DIR = path.resolve(__dirname, '../../../data');
const DB_PATH = path.join(DATA_DIR, 'artele.db');

let _db = null;

export function getDb() {
  if (!_db) {
    mkdirSync(DATA_DIR, { recursive: true });
    _db = new Database(DB_PATH);
    _db.pragma('journal_mode = WAL');
    initSchema(_db);
  }
  return _db;
}

function initSchema(db) {
  db.exec(`
    CREATE TABLE IF NOT EXISTS settings (
      id INTEGER PRIMARY KEY,
      name TEXT,
      timePerArtwork INTEGER NOT NULL DEFAULT 10,
      matColor TEXT NOT NULL DEFAULT '#333333',
      paused INTEGER NOT NULL DEFAULT 0,
      amOnWeekday INTEGER NOT NULL DEFAULT 6,
      amOffWeekday INTEGER NOT NULL DEFAULT 10,
      pmOnWeekday INTEGER NOT NULL DEFAULT 17,
      pmOffWeekday INTEGER NOT NULL DEFAULT 19,
      activeWeekday INTEGER NOT NULL DEFAULT 1,
      amOnWeekend INTEGER NOT NULL DEFAULT 6,
      amOffWeekend INTEGER NOT NULL DEFAULT 7,
      pmOnWeekend INTEGER NOT NULL DEFAULT 17,
      pmOffWeekend INTEGER NOT NULL DEFAULT 19,
      activeWeekend INTEGER NOT NULL DEFAULT 1
    );

    CREATE TABLE IF NOT EXISTS sources (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      name TEXT NOT NULL,
      active INTEGER NOT NULL DEFAULT 1,
      accessToken TEXT,
      departmentIDs TEXT,
      departmentObjectAPI TEXT,
      departmentArray TEXT,
      departmentObjectField TEXT,
      objectAPI TEXT NOT NULL,
      imageField TEXT NOT NULL,
      titleField TEXT NOT NULL,
      artistField TEXT NOT NULL,
      dateField TEXT NOT NULL,
      mediumField TEXT NOT NULL,
      objectIDs TEXT
    );
  `);

  const { count } = db.prepare('SELECT COUNT(*) as count FROM settings').get();
  if (count === 0) seedDefaults(db);
}

