function seedDefaults(db) {
  db.prepare(`
    INSERT INTO settings
      (id, name, timePerArtwork, matColor, paused,
       amOnWeekday, amOffWeekday, pmOnWeekday, pmOffWeekday, activeWeekday,
       amOnWeekend, amOffWeekend, pmOnWeekend, pmOffWeekend, activeWeekend)
    VALUES (1, 'Settings', 10, '#333333', 0, 6, 10, 17, 19, 1, 6, 7, 17, 19, 1)
  `).run();

  const insert = db.prepare(`
    INSERT INTO sources
      (name, active, accessToken, departmentIDs, departmentObjectAPI,
       departmentArray, departmentObjectField, objectAPI, imageField,
       titleField, artistField, dateField, mediumField, objectIDs)
    VALUES
      (@name, @active, @accessToken, @departmentIDs, @departmentObjectAPI,
       @departmentArray, @departmentObjectField, @objectAPI, @imageField,
       @titleField, @artistField, @dateField, @mediumField, @objectIDs)
  `);

  for (const src of SEED_SOURCES) {
    insert.run(src);
  }

  console.log('Database seeded with default settings and sources.');
}
